from flask import Flask, request, jsonify
import pandas as pd
import tensorflow as tf
from tensorflow import keras
import os
import re
import json
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads/'
app.config['ALLOWED_EXTENSIONS'] = {'csv', 'jpg', 'jpeg', 'png'}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

def validate_csv(file):
    try:
        df = pd.read_csv(file)
        # Basic validation: Check for required columns
        if not all(col in df.columns for col in ['image_path', 'label']):
            return False
        return True
    except Exception:
        return False

def validate_image(image_path):
    return os.path.isfile(image_path) and re.match(r'.*\.(jpg|jpeg|png)$', image_path)

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '' or not allowed_file(file.filename):
        return jsonify({'error': 'Invalid file type'}), 400
    filename = secure_filename(file.filename)
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(file_path)

    if filename.endswith('.csv'):
        if not validate_csv(file_path):
            return jsonify({'error': 'Invalid CSV format'}), 400
        # Load and process CSV
        df = pd.read_csv(file_path)
        for _, row in df.iterrows():
            if not validate_image(row['image_path']):
                return jsonify({'error': f'Invalid image path: {row["image_path"]}'}), 400
        # Train model with new data
        train_model(df)
    else:
        # Process image upload
        # Add image to training dataset
        pass

    return jsonify({'success': 'File uploaded successfully'}), 200

def train_model(df):
    # Load images and labels
    images = []
    labels = []
    for _, row in df.iterrows():
        img = keras.preprocessing.image.load_img(row['image_path'], target_size=(150, 150))
        img_array = keras.preprocessing.image.img_to_array(img)
        images.append(img_array)
        labels.append(row['label'])
    
    images = tf.convert_to_tensor(images)
    labels = tf.convert_to_tensor(labels)

    # Define model
    model = keras.Sequential([
        keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(150, 150, 3)),
        keras.layers.MaxPooling2D(pool_size=(2, 2)),
        keras.layers.Flatten(),
        keras.layers.Dense(128, activation='relu'),
        keras.layers.Dense(len(set(labels.numpy())), activation='softmax')
    ])

    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    model.fit(images, labels, epochs=5)

    # Save model securely
    model.save('model.h5')

if __name__ == '__main__':
    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
    app.run(host='0.0.0.0', port=5000)